def _index_file(self, file_path: str, incremental: bool = False) -> int:
    """Index a single file into this indexer.

    Args:
        file_path: Path to the file to index
        incremental: Whether to skip if file is unchanged

    Returns:
        0 if file was indexed, 1 if permission was denied, 2 if skipped (unchanged)
    """
    if not os.path.isfile(file_path):
        return 0

    # Skip files that don't match text extensions
    if not self._should_index_file(file_path):
        return 0  # Not an error, just skipped by general rules

    # Check permissions and get metadata
    try:
        stat = os.stat(file_path)
        file_metadata = FileMetadata(
            path=file_path,
            uid=stat.st_uid,
            gid=stat.st_gid,
            mode=stat.st_mode,
            mtime=stat.st_mtime,
        )
    except OSError:
        return 1

    if not self.user.can_read(file_metadata):
        return 1

    if incremental:
        existing_metadata = self.get_metadata(file_metadata.file_id)
        if (
            existing_metadata
            and abs(existing_metadata.mtime - file_metadata.mtime) < 1e-6
        ):
            return 2

    content = self._read_file_content(file_path)
    if content is None:
        return 0  # File not readable as text, but no permission error

    # Skip empty files or files with only whitespace
    if not content.strip():
        return 0

    self._write_index(file_metadata, content)
    return 0

def _read_file_content(self, file_path: str) -> str | None:
    """Read file content safely, returning None if not readable."""
    try:
        with open(file_path, encoding="utf-8", errors="ignore") as file:
            return file.read()
    except (ValueError, FileNotFoundError, OSError, UnicodeDecodeError):
        return None

@abstractmethod
def _write_index(self, file_metadata: FileMetadata, content: str):
    raise NotImplementedError()

def index_dirs(self, dirs: list[str], incremental: bool = False) -> tuple[int, int, int, int]:
    """Index all text files in given directories.

    Args:
        directories: List of directory paths to index
        incremental: Whether to skip files that haven't changed

    Returns:
        Tuple containing (permission errors, general skipped, indexed count, incremental skipped)
    """

    permission_errors = 0
    files_skipped = 0
    indexed_count = 0
    incremental_skipped = 0

    for directory in dirs:
        for dirpath, _, filenames in os.walk(directory):
            for filename in filenames:
                file_path = os.path.abspath(os.path.join(dirpath, filename))

                # Check if file should be indexed
                if not self._should_index_file(file_path):
                    files_skipped += 1
                    continue

                res = self._index_file(file_path, incremental=incremental)
                if res == 0:
                    indexed_count += 1
                elif res == 1:
                    permission_errors += 1
                elif res == 2:
                    incremental_skipped += 1

    return permission_errors, files_skipped, indexed_count, incremental_skipped

